-- ── 3. Computer Network Support Specialists (15-1231.00) ────
INSERT INTO agent_logic (primary_directive, step_by_step_json, toolbox_requirements) VALUES (
'Analyze, test, troubleshoot, and evaluate existing network systems including LAN, WAN, and cloud networks to maintain reliable and secure connectivity.',
