  {"step":2,"type":"tool_use","name":"identify_root_cause","description":"Trace networking problems to root cause using diagnostic software and equipment","input":{"action":"root_cause_analysis","tools":["CiscoWorks","HP_Network_Node_Manager","PowerShell"],"methods":["packet_capture","log_analysis","topology_review"]},"definition_of_done":"Root cause documented with supporting evidence, ticket updated"},
  {"step":3,"type":"tool_use","name":"configure_fix","description":"Apply configuration changes to routers, switches, and security settings","input":{"action":"apply_remediation","platforms":["Windows_Server","Linux","Cisco_IOS"],"tools":["Python","PowerShell"]},"definition_of_done":"Configuration change applied, change log updated, rollback plan documented"},
  {"step":4,"type":"tool_use","name":"verify_resolution","description":"Retest network after fix to confirm problem is resolved and performance restored","input":{"action":"post-fix_validation","tools":["Wireshark","Nagios","Splunk_Enterprise"],"thresholds":{"latency_ms":50,"packet_loss_pct":0}},"definition_of_done":"Network metrics within SLA, no recurrence within 24h monitoring window"},
  {"step":5,"type":"tool_use","name":"document_and_report","description":"Document network support activities, breaches, and resolution steps","input":{"action":"document","tools":["ServiceNow","Confluence","JIRA"],"artifacts":["incident_report","network_topology_update"]},"definition_of_done":"Incident closed in ticketing system, topology diagrams updated"},
  {"step":6,"type":"tool_use","name":"backup_and_harden","description":"Back up network configurations and apply security hardening measures","input":{"action":"backup_and_secure","tools":["Splunk","IBM_WebSphere","firewall_mgmt"],"schedule":"weekly_config_backup"},"definition_of_done":"Backup verified restorable, security scan shows no new vulnerabilities"}
]'::jsonb,
ARRAY['Wireshark','Nagios','OmniPeek','CiscoWorks','HP Network Node Manager','Splunk Enterprise','PowerShell','Python','Windows Server','Linux','UNIX','MySQL','SQL Server','Teradata']
);

